package com.wjx871.population.export;import java.io.*;import java.nio.file.*;import java.security.*;import java.util.*;import org.apache.poi.ss.usermodel.*;import org.apache.poi.xssf.usermodel.XSSFWorkbook;import org.springframework.core.io.*;import org.springframework.stereotype.Service;
@Service class ExportFileService {private final Path root;ExportFileService(ExportProperties p)throws IOException{root=Path.of(p.getDir()).toAbsolutePath().normalize();Files.createDirectories(root);}Generated generate(String module,List<String> fields,List<Map<String,Object>> rows,String stored)throws Exception{Path target=safe(stored),tmp=safe(stored+".tmp");try(Workbook wb=new XSSFWorkbook()){Sheet sheet=wb.createSheet(module);Row h=sheet.createRow(0);for(int i=0;i<fields.size();i++)h.createCell(i).setCellValue(fields.get(i));for(int n=0;n<rows.size();n++){Row r=sheet.createRow(n+1);for(int i=0;i<fields.size();i++){Object v=value(rows.get(n),fields.get(i));r.createCell(i,CellType.STRING).setCellValue(cell(v));}}try(OutputStream out=Files.newOutputStream(tmp,StandardOpenOption.CREATE_NEW)){wb.write(out);}}try{Files.move(tmp,target,StandardCopyOption.ATOMIC_MOVE);}catch(AtomicMoveNotSupportedException e){Files.move(tmp,target);}byte[] digest=MessageDigest.getInstance("SHA-256").digest(Files.readAllBytes(target));return new Generated(target,HexFormat.of().formatHex(digest),Files.size(target));}Resource load(String stored)throws IOException{Path p=safe(stored);if(!Files.isRegularFile(p))throw new FileNotFoundException();return new FileSystemResource(p);}boolean delete(String stored)throws IOException{return Files.deleteIfExists(safe(stored));}void quietDelete(String stored){try{delete(stored);}catch(IOException ignored){}}private Path safe(String n){if(n==null||!n.matches("[A-Za-z0-9._-]+"))throw new IllegalArgumentException("非法存储文件名");Path p=root.resolve(n).normalize();if(!p.startsWith(root))throw new IllegalArgumentException("非法导出路径");return p;}private Object value(Map<String,Object> row,String field){for(var e:row.entrySet())if(e.getKey().equalsIgnoreCase(field))return e.getValue();String actual=switch(field){case"maskedIdentityNo"->"identityNo";case"maskedPhone"->"phone";case"maskedPermitNo"->"permitNo";default->field;};for(var e:row.entrySet())if(e.getKey().equalsIgnoreCase(actual))return e.getValue();return null;}private String cell(Object v){if(v==null)return "";String s=String.valueOf(v);return !s.isEmpty()&&"=+-@".indexOf(s.charAt(0))>=0?"'"+s:s;}record Generated(Path path,String sha256,long size){}}
